mapper.select:
SELECT r.report_id, r.student_id, u.real_name AS student_name, u.student_no, r.topic_id, t.topic_name, r.arrangement_id, r.document_id, d.file_name AS document_name, r.submit_time, r.review_status, r.review_comment, r.reviewer_id, ru.real_name AS reviewer_name, r.review_time, r.create_time, r.update_time FROM opening_report r LEFT JOIN user_info u ON r.student_id = u.user_id LEFT JOIN topic_info t ON r.topic_id = t.topic_id LEFT JOIN document_info d ON r.document_id = d.document_id LEFT JOIN user_info ru ON r.reviewer_id = ru.user_id WHERE r.is_deleted = 0
AND u.enterprise_id = #{enterpriseId}
AND u.real_name LIKE CONCAT('%', #{studentName}, '%')
AND r.review_status = #{reviewStatus}
AND r.arrangement_id = #{arrangementId}
ORDER BY r.create_time DESC
